const test = require("node:test");
const assert = require("node:assert");
const { make } = require("../src/event.js");
const { Store } = require("../src/store.js");
const { encodeAll } = require("../src/encodeAll.js");
const { verify } = require("../src/verify.js");
const { emit } = require("../src/emit.js");
const { all } = require("../src/index.js");

const TYPE_RE = /^[a-z]+(-[a-z]+)*$/;

test("emit dispatches every handler through the migrated API", () => {
  assert.strictEqual(emit({ type: "ping", payload: { n: 1 } }), "ping:1");
  assert.strictEqual(emit({ type: "pong", payload: { n: 2 } }), "pong:2");
  assert.strictEqual(emit({ type: "tick", payload: { n: 3 } }), "tick:3");
});

test("encode/verify roundtrip holds for a store of events", () => {
  const store = new Store();
  store.add(make("ping", { n: 1 }));
  store.add(make("pong", { n: 2 }));
  store.add(make("tick", { n: 3 }));
  const encoded = encodeAll(store);
  assert.strictEqual(encoded.length, 3);
  for (const s of encoded) {
    assert.strictEqual(verify(s), true, `verify failed for ${s}`);
  }
  const tampered = encoded[0].split("#")[0] + "#99";
  assert.strictEqual(verify(tampered), false);
});

test("every registered handler conforms to the convention", () => {
  const handlers = all();
  assert.ok(handlers.length >= 3);
  for (const h of handlers) {
    assert.ok(TYPE_RE.test(h.type), `type not kebab-case: ${h.type}`);
    assert.strictEqual(h.handle({ payload: { n: 5 } }), `${h.type}:5`);
  }
});
